// ─── locale detection (same as whitepaper-client pattern) ───────────────────
function detectLocale(): "en" | "ko" | "ja" {
  if (typeof window === "undefined") return "en"
  try {
    const urlLang = new URLSearchParams(window.location.search).get("lang")
    if (urlLang === "ko" || urlLang === "ja" || urlLang === "en") return urlLang
    const stored = localStorage.getItem("locale")
    if (stored === "ko" || stored === "ja") return stored
  } catch {}
  return "en"
}

// ─── Language toggle button ─────────────────────────────────────────────────
function LangToggle({
  active,
  onChange,
}: {
  active: "en" | "ko" | "ja"
  onChange: (l: "en" | "ko" | "ja") => void
}) {
  const langs: { key: "en" | "ko" | "ja"; label: string }[] = [
    { key: "en", label: "EN" },
    { key: "ko", label: "KO" },
    { key: "ja", label: "JA" },
  ]
  return (
    <div className="flex gap-1 mb-8">
      {langs.map(({ key, label }) => (
        <button
          key={key}
          onClick={() => onChange(key)}
          className={`px-3 py-1 rounded-full text-xs font-medium border transition-colors ${
            active === key
              ? "bg-primary text-primary-foreground border-primary"
              : "border-border text-muted-foreground hover:text-foreground"
          }`}
        >
          {label}
        </button>
      ))}
    </div>
  )
}

