export default function TermsPage() {
  const [lang, setLang] = useState<"en" | "ko" | "ja">("en")

  useEffect(() => {
    setLang(detectLocale())
  }, [])

  const titles: Record<"en" | "ko" | "ja", string> = {
    en: "Terms of Service",
    ko: "\uc774\uc6a9\uc57d\uad00",
    ja: "\u5229\u7528\u898f\u7d04",
  }
  const dates: Record<"en" | "ko" | "ja", string> = {
    en: "Last updated: 2 May 2026",
    ko: "\ucd5c\uc885 \uc218\uc815\uc77c: 2026\ub144 5\uc6d4 2\uc77c",
    ja: "\u6700\u7d42\u66f4\u65b0\u65e5: 2026\u5e745\u67082\u65e5",
  }

  return (
    <main className="min-h-screen">
      <Navbar />
      <div className="pt-page pb-16">
        <div className="mx-auto max-w-3xl px-4 sm:px-6">
          <h1 className="text-3xl md:text-4xl font-serif text-primary mb-2">{titles[lang]}</h1>
          <p className="text-sm text-muted-foreground mb-6">{dates[lang]}</p>
          <LangToggle active={lang} onChange={setLang} />
          {lang === "ko" ? <TermsKO /> : lang === "ja" ? <TermsJA /> : <TermsEN />}
        </div>
      </div>
      <Footer />
    </main>
  )
}
